import React, { useEffect, useState } from "react";

// Backend URL
const apiBase =
  process.env.REACT_APP_API_URL || "https://prasa-app-yde3.onrender.com";

const AddTravel = ({ employee }) => {
  const [form, setForm] = useState({
    travel_date: "",
    purpose: "",
    location_from: "",
    location_to: "",
    mode_of_travel: "",
    amount: "",
    status: "Pending",
  });

  const [travelList, setTravelList] = useState([]);
  const [loading, setLoading] = useState(false);
  const [editingId, setEditingId] = useState(null); // travel_id
  const [message, setMessage] = useState("");

  const empld = employee?.empld || employee?.emp_code || employee?.login_id;

  // Load travel history
  const loadTravel = async () => {
    if (!empld) return;
    try {
      setLoading(true);
      const res = await fetch(
        `${apiBase}/travel-expenses?empld=${encodeURIComponent(empld)}`
      );
      if (!res.ok) throw new Error("Server error");

      const data = await res.json();
      setTravelList(data || []);
      setMessage("");
    } catch (err) {
      console.error("Load travel error:", err);
      setMessage("❌ Could not load travel expenses.");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    loadTravel();
  }, [empld]);

  const handleChange = (field, value) => {
    setForm((prev) => ({ ...prev, [field]: value }));
  };

  // Save or Update Travel Expense
  const handleSubmit = async (e) => {
    e.preventDefault();
    setMessage("");

    if (!empld) {
      setMessage("❌ Missing employee ID.");
      return;
    }

    try {
      const url =
        editingId == null
          ? `${apiBase}/travel-expenses`
          : `${apiBase}/travel-expenses/${editingId}`;

      const method = editingId == null ? "POST" : "PUT";

      const body = {
        empld,
        travel_date: form.travel_date,
        purpose: form.purpose,
        location_from: form.location_from,
        location_to: form.location_to,
        mode_of_travel: form.mode_of_travel,
        amount: parseFloat(form.amount || 0),
        status: form.status || "Pending",
      };

      const res = await fetch(url, {
        method,
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(body),
      });

      const data = await res.json();

      if (!data.success) {
        setMessage("❌ " + (data.message || "Failed to save travel expense."));
      } else {
        setMessage(
          editingId == null
            ? "✅ Travel expense added."
            : "✅ Travel expense updated."
        );

        setEditingId(null);
        setForm({
          travel_date: "",
          purpose: "",
          location_from: "",
          location_to: "",
          mode_of_travel: "",
          amount: "",
          status: "Pending",
        });

        loadTravel();
      }
    } catch (err) {
      console.error("Submit travel error:", err);
      setMessage("❌ Server error while saving travel expense.");
    }
  };

  const startEdit = (row) => {
    setEditingId(row.travel_id);
    setForm({
      travel_date: row.travel_date?.substring(0, 10) || "",
      purpose: row.purpose || "",
      location_from: row.location_from || "",
      location_to: row.location_to || "",
      mode_of_travel: row.mode_of_travel || "",
      amount: String(row.amount || ""),
      status: row.status || "Pending",
    });
  };

  const deleteRow = async (row) => {
    if (!window.confirm("Delete this travel expense?")) return;

    try {
      const res = await fetch(`${apiBase}/travel-expenses/${row.travel_id}`, {
        method: "DELETE",
      });
      const data = await res.json();

      if (!data.success) {
        setMessage("❌ " + (data.message || "Failed to delete."));
      } else {
        setMessage("✅ Travel expense deleted.");
        loadTravel();
      }
    } catch (err) {
      console.error("Delete travel error:", err);
      setMessage("❌ Server error while deleting.");
    }
  };

  return (
    <div className="add-expense-page">
      <h2>Travel Expense</h2>

      {/* FORM */}
      <form className="expense-form" onSubmit={handleSubmit}>
        <div className="form-row">
          <label>Date</label>
          <input
            type="date"
            value={form.travel_date}
            onChange={(e) => handleChange("travel_date", e.target.value)}
            required
          />
        </div>

        <div className="form-row">
          <label>From</label>
          <input
            type="text"
            value={form.location_from}
            onChange={(e) => handleChange("location_from", e.target.value)}
            required
          />
        </div>

        <div className="form-row">
          <label>To</label>
          <input
            type="text"
            value={form.location_to}
            onChange={(e) => handleChange("location_to", e.target.value)}
            required
          />
        </div>

        <div className="form-row">
          <label>Mode of Travel</label>
          <input
            type="text"
            value={form.mode_of_travel}
            onChange={(e) => handleChange("mode_of_travel", e.target.value)}
          />
        </div>

        <div className="form-row">
          <label>Purpose</label>
          <input
            type="text"
            value={form.purpose}
            onChange={(e) => handleChange("purpose", e.target.value)}
            required
          />
        </div>

        <div className="form-row">
          <label>Amount (₹)</label>
          <input
            type="number"
            value={form.amount}
            onChange={(e) => handleChange("amount", e.target.value)}
            required
          />
        </div>

        <div className="form-row">
          <label>Status</label>
          <select
            value={form.status}
            onChange={(e) => handleChange("status", e.target.value)}
          >
            <option value="Pending">Pending</option>
            <option value="Approved">Approved</option>
            <option value="Rejected">Rejected</option>
          </select>
        </div>

        <button type="submit" className="btn-primary">
          {editingId ? "Save Changes" : "Add Travel Expense"}
        </button>
      </form>

      {message && <p className="status-message">{message}</p>}

      {/* HISTORY TABLE */}
      <h3>Travel Expense History</h3>

      {loading ? (
        <p>Loading...</p>
      ) : travelList.length === 0 ? (
        <p>No travel expenses found.</p>
      ) : (
        <table className="expense-table">
          <thead>
            <tr>
              <th>Date</th>
              <th>From</th>
              <th>To</th>
              <th>Purpose</th>
              <th>Mode</th>
              <th>Amount</th>
              <th>Status</th>
              <th style={{ width: 130 }}>Actions</th>
            </tr>
          </thead>

          <tbody>
            {travelList.map((row) => (
              <tr key={row.travel_id}>
                <td>{row.travel_date?.substring(0, 10)}</td>
                <td>{row.location_from}</td>
                <td>{row.location_to}</td>
                <td>{row.purpose}</td>
                <td>{row.mode_of_travel}</td>
                <td>₹{row.amount}</td>
                <td>{row.status || "Pending"}</td>
                <td>
                  <button className="btn-link" onClick={() => startEdit(row)}>
                    Edit
                  </button>
                  <button
                    className="btn-link danger"
                    onClick={() => deleteRow(row)}
                  >
                    Delete
                  </button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      )}
    </div>
  );
};

export default AddTravel;
